var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 9월 25일 런던, <color=#ffd34c>■■ ■■■</color> 지하 사원","JPN":"1888年9月25日　ロンドン、<color=#ffd34c>■■ ■■■</color>地下の寺院","ENG":"September 25, 1888, London, <color=#ffd34c>■■ ■■■</color> Underground Temple","TWN":"1888年9月25日 倫敦，<color=#ffd34c>■■ ■■■</color> 地下神廟"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"우리 모두 기도합시다.","JPN":"皆、祈りを捧げましょう。","ENG":"Let us all pray.","TWN":"讓我們一起祈禱吧。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"이 의식을 통하여, 무가치한 저들이 유의미한 존재로 탈바꿈할 수 있도록 기도합시다.","JPN":"この儀式によって、無価値な彼らが意味のある存在として生まれ変われるよう、祈りを捧げましょう。","ENG":"Pray that our unworthiness will be transformed into meaningfulness through this ritual.","TWN":"透過這個儀式，祈禱那些毫無價值之人能夠變成有意義的存在。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>마그눔 오푸스</color>를 위한 기도를…….","JPN":"<color=#ffd34c>マグヌム・オプス</color>のための祈りを……","ENG":"Pray for <color=#ffd34c>Magnum Opus</color>...","TWN":"祈禱<color=#ffd34c>偉大傑作</color>……"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"천국의 회합을 가리던 장막은 모두 거두어졌으니.","JPN":"天国の会合を隠していたベールはすべて片付いた。","ENG":"As the veil covering the assembly of heaven has been drawn.","TWN":"遮蔽天國聚會的帷幕已被全部揭開。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"영혼을 신과 하나되게 하고, 소세계를 대세계와 하나되게 하고.","JPN":"魂と神を一つにし、小世界と大世界を一つにし。","ENG":"Let the soul become one with god, the small and big world unite.","TWN":"讓靈魂與神合一，讓小世界與大世界合一。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"여성성과 남성성을 하나되게 하고, 자아와 무자아를 하나되게 하소서.","JPN":"女性性と男性性を一つにし、自我と無我を一つにしたまえ。","ENG":"Let the two halves of men and women join together, and the self and selfless bond.","TWN":"讓女性與男性合一，讓自我與無我合一。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORAN_SWANSONG_NPC_NULL","text":{"KOREA":"지시하신 대로 경찰청과 신문사에 성명문을 전달하였습니다.","JPN":"指示どおり、警察庁と新聞社に声明文を伝えました。","ENG":"As you instructed, I have delivered the statement to the police and media.","TWN":"按照你的指示，已將聲明傳達給警察局和報社了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"……고생했네.","JPN":"……ご苦労だった。","ENG":"...Good work.","TWN":"……辛苦了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORAN_SWANSONG_NPC_NULL","text":{"KOREA":"한 가지, 궁금한 걸 여쭈어봐도 괜찮겠습니까?","JPN":"一つ、お聞きしてもよろしいでしょうか。","ENG":"May I ask one thing?","TWN":"有一件事，我可以問一下嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORAN_SWANSONG_NPC_NULL","text":{"KOREA":"복수귀의 실력을 의심하는 건 아니지만, 이런 식으로 단서를 남길 필요가 있을까요?","JPN":"復讐鬼の腕を疑っているわけではありませんが、こうして手がかりを残す必要がありますか。","ENG":"Though I do not doubt the Revenger, was it necessary to leave clues behind like this?","TWN":"我並不是懷疑復仇鬼的實力，但有必要這樣留下線索嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORAN_SWANSONG_NPC_NULL","text":{"KOREA":"추적당할 텐데요.","JPN":"追跡されやすくなりますが。","ENG":"Someone will start following them.","TWN":"總會被有心人追蹤到的。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"괜찮아. 심볼이라는 건 의식에서 아주 중요한 의미를 가지거든.","JPN":"大丈夫だ。シンボルというのは儀式で非常に重要な意味を持つ。","ENG":"No matter. Symbols have significant importance in rituals.","TWN":"沒關係。象徵在儀式中有著非常重要的意義。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"그저 별것도 아닌, 살인이 거창한 의미를 가지게 되고.","JPN":"大したことでもない殺人が仰々しい意味を持つようになり、","ENG":"The killing may seem like nothing, but it will take on a greater meaning.","TWN":"殺戮原本只不過是件微不足道的事情，但卻會因此變得意義重大。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"우매한 대중들은 그로 하여금 경외심마저 품게 되겠지.","JPN":"愚かな大衆は畏敬の念すら抱くだろう。","ENG":"The ignorant public will be in awe.","TWN":"愚昧的群眾甚至會對此心生敬畏。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"부정적 감정과 집단 무의식의 발현은 결국 불가능한 일을 현실로 만들어 줄 거라네.","JPN":"ネガティブな感情と、集合的無意識の発現は不可能なことを現実にさせてくれる。","ENG":"The negative emotions and the manifestation of the collective unconscious will turn the impossible into reality.","TWN":"負面情感和集體無意識的顯現，最終會將不可能的事情變為現實。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"내 최후의 걸작, <color=#ffd34c>심야의 살인마</color>라는 심볼에 의해서 말이야.","JPN":"私の最後の傑作、<color=#ffd34c>深夜の殺人鬼</color>というシンボルによってな。","ENG":"With my final masterpiece, a symbol called the <color=#ffd34c>Midnight Killer</color>, that is.","TWN":"我的最後傑作，由<color=#ffd34c>午夜殺人魔</color>這個象徵所引導。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"subtitle","speaker":null,"text":{"KOREA":"같은 시간\\n로열 오페라 하우스","JPN":"同時刻\\nロイヤルオペラハウス","ENG":"Same time.\\nRoyal Opera House","TWN":"同一時間\\n皇家歌劇院"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"커튼콜은 여기까지.","JPN":"カーテンコールはここまで。","ENG":"This is where the curtain call ends.","TWN":"謝幕演出到此結束。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"신사 숙녀 여러분, 저희 무대를 보러 와 주셔서 감사합니다.","JPN":"レディースアンドジェントルマン、私たちの舞台を見に来ていただきありがとうございました。","ENG":"Ladies and gentlemen, thank you all for coming tonight to see our performance.","TWN":"女士們先生們，感謝大家前來觀看。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……다음에도.","JPN":"……次回も。","ENG":"...I'll be waiting.","TWN":"……下次也是。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"다음에도 인연이 닿을 수 있도록, 이곳에서 여러분을 기다리고 있을게요.","JPN":"このご縁がこの先も続きますように、私はここで皆さんをお待ちしています。","ENG":"I will be waiting to see you all again if fate allows it.","TWN":"希望下次還能有緣相見，我會在這裡等著大家。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"Whew...","TWN":"呼……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"오늘 무대도 고생 많았어, 스완.","JPN":"今日の舞台もお疲れさま、スワン。","ENG":"You were great tonight, Swan.","TWN":"今天的演出也辛苦了，史旺。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"고마워 메리 제인.","JPN":"ありがとう、メリー・ジェーン。","ENG":"Thanks, Mary Jane.","TWN":"謝謝你，瑪麗·珍。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"무대에서 썼던 마도구들 정리하는 거지? 나도 좀 도와줄까?","JPN":"舞台で使った魔道具を片付けるのね？　私も手伝おうか？","ENG":"Are you putting away the Curio used on stage back? Do you want some help?","TWN":"你在整理舞台上用的魔法道具嗎？要我幫忙嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"아니야. 배우는 쉴 수 있을 때 쉬어 둬야지. 이런 거 하라고 스태프가 있는 거잖아.","JPN":"役者は休める時にちゃんと休んでおかないと。こういう仕事をするために、私たちスタッフがいるんだから。","ENG":"No. You should rest while you can. Plus, this is what I was hired to do.","TWN":"不用了。演員要在能休息的時候休息。這種事就交給幕後來做。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"이제 거울이랑 확성기만 정리하면 되는 걸?","JPN":"あとは鏡とメガホンだけ片付けたら終わるよ。","ENG":"All that's left is putting back the mirror and the megaphone.","TWN":"現在只剩下整理鏡子和擴音器了吧？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"그건 그렇고 오늘도 계시더라, 그 멋진 신사분?","JPN":"そういえば、今日も来たんだね。あの素敵な紳士さん。","ENG":"Besides that, I saw him in the audience tonight as well. You know, that handsome gentleman.","TWN":"話說回來，今天也在啊，那位帥氣的紳士？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"으, 으응…….","JPN":"う、うん……","ENG":"Y-yeah...","TWN":"呃，呃嗯……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"팬이라더니. 아주 네 매력에 푹 빠지셨나 봐~","JPN":"あなたの魅力にどっぷりはまったんじゃないの～？","ENG":"He said he's a fan of yours. Guess he's really into you, huh?","TWN":"他說是你的粉絲呢。看來是徹底被你的魅力迷住了～"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"왕실 우표까지 펑펑 써가면서 팬레터를 보내시던 분이니까. 틀림없이 귀족이시겠지?","JPN":"王室の切手まで使ってファンレターを送ってたぐらいだし、きっと貴族の方だよね。","ENG":"He's been sending you fan letters with the royal stamps all this time, so he must be a noble, right?","TWN":"他就是那個大手大腳地用王室郵票寄信的人吧。肯定是個貴族吧～！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 어쩜~ 얌전한 고양이가 부뚜막에 먼저 올라간다더니~","JPN":"ふふ、あなたも大人しい顔してすごいよね～","ENG":"Haha. They say it's always the quiet ones and it turns out they're right!","TWN":"哈哈，人家都說，惦惦吃三碗公～"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"그동안 연애 같은 건 관심 없다고 했으면서, 대체 그런 분을 어디서 만났을까~?","JPN":"今まで恋愛なんて興味ないって言ってたのに、どこであんな方に出会えたの～？","ENG":"You were always saying to me that you weren't interested in dating anyone. But how did you snatch such a fine gentleman?","TWN":"你之前還一直說對戀愛沒興趣，到底是在哪裡遇到那樣的人的～?"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"이 언니한테만 살짝 얘기해주면 안 돼?","JPN":"私にだけこっそり、教えてくれない？","ENG":"Mind telling me how you two met?","TWN":"能稍微告訴姊姊一下嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"큿. 그건, 그러니까…….","JPN":"そっ、それは、その……","ENG":"Erm, that's... Well...","TWN":"呃。那，那個……就是……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"하긴, 뭐. 스완은 런던에서 가장 인기 있는 프리마돈나니까.","JPN":"まあ、スワンはロンドンで一番人気のプリマドンナだし。","ENG":"Then again, you are the most popular prima donna in London.","TWN":"也對喔，史旺你是倫敦最受歡迎的首席女演員。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"그 정도 수준 있는 신사분이 아니라면…….","JPN":"あのぐらいのレベルの紳士の方じゃないと……","ENG":"I'm sure your standards of men are pretty high...","TWN":"如果不是那種有品位的紳士……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그런 거 아니라고오오……!!","JPN":"そんなんじゃないの……！！","ENG":"It's not like that...!","TWN":"才不是那樣的啊啊啊啊……！！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"정말이지! 대체 무슨 생각을 하시는 건가요?","JPN":"もう！　いったい何を考えているんですか？","ENG":"Ugh! What on earth were you thinking?","TWN":"真的！你到底在想什麼呢？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"으음? 왜 그러지?","JPN":"む？　どうした？","ENG":"Hmm? What's wrong?","TWN":"嗯？怎麼了？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"몰라서 묻나요? 왜 매일 같이 공연을 보러 오는 건데요?","JPN":"とぼけないでください。なんで毎日公演を見に来るのか聞いているのです。","ENG":"Are you seriously that oblivious? Why are you coming to see me perform every night?","TWN":"你是明知故問嗎？為什麼每天都來看演出？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"수사에 도움이 필요한 거라면, 그냥 끝나고 조용히 부르세요.","JPN":"捜査を手伝ってほしいなら、公演後にこっそり呼び出せばいいじゃないですか。","ENG":"If you need help with your investigation, just call me quietly after the show.","TWN":"如果要協助調查的話，不能等結束後悄悄叫我嗎！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"배우한테 이미지가 얼마나 중요한지 알기나 해요? 벌써 극단에 소문이 쫙 퍼졌다고요!","JPN":"俳優にとってイメージがどれだけ大事なものなのか、わかりますか？　もう劇団に噂が広まってしまいましたよ！","ENG":"Don't you know how important reputation is to an actress? The entire theater is already spreading rumors!","TWN":"你知道形象對演員有多重要？現在整個劇團都傳開了！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하하, 무슨 말을 하나 했더니.","JPN":"はは、何を言い出すのかと思ったら。","ENG":"Haha. That's what you were talking about.","TWN":"哈哈，我還以為你在說什麼呢。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"말하지 않았나, 나는 자네의 팬이라고.","JPN":"言っただろう？　私は君のファンなんだ。","ENG":"But didn't I say? I'm your fan.","TWN":"我不是說過了嗎，我是你的粉絲。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"좋아하는 배우의 공연을 제값 주고 보러 왔을 뿐인데, 무슨 문제라도?","JPN":"好きな俳優の公演をチケット代を払って見に来ただけなのに、何か問題でも？","ENG":"What's the problem of paying good money to see my favorite actress perform?","TWN":"我只是花錢來看我喜歡的演員的表演，有什麼問題嗎？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……으으!","JPN":"……うう！","ENG":"...Errgh!","TWN":"……呃！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아, 참고로 오늘 공연도 무척이나 훌륭했다네.","JPN":"ああ、ちなみに今日の公演もとても素晴らしかったよ。","ENG":"Oh, by the way, tonight's performance was excellent as usual.","TWN":"啊，順便說一下，今天的演出也非常精彩。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"파노라마라고 했나? 배역이 바뀔 때마다 순식간에 모습을 바꿀 수 있다니.","JPN":"パノラマ、だったかね。役が変わるたびに一瞬で姿を変えられるとは。","ENG":"Panorama, was it? I still can't believe you can change your appearance in an instant every time you change roles.","TWN":"是叫全景的道具，對嗎？每次切換角色的時候形象也能隨之瞬間改變。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"왕실에서 마도구를 지원받는 극장은 역시 연출 수준이 높더군.","JPN":"王室から魔道具の支援を受けている劇場は、さすが演出のレベルが高いな。","ENG":"A theater that the royal family provides Curio to is truly on another level.","TWN":"真不愧是王室資助的魔法劇院啊，舞台水準確實很高。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"물론, 자네의 연기가 워낙 출중해서 더 돋보였지만.","JPN":"もちろん、君の素晴らしい演技があってこそ、演出も輝いたのだと思うがね。","ENG":"Of course, your outstanding acting was the star of the show.","TWN":"當然，你的演技本來就很出色，所以就更加引人注目了。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"마음에도 없는 소리는 그쯤 하시죠.","JPN":"心にもないことを言うのはやめてください。","ENG":"Enough with the flattery.","TWN":"口是心非的話就到此為止吧。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신이랑 이야기하고 있으면 바보가 될 것 같으니까.","JPN":"あなたと話すとこっちもバカになりそうですから。","ENG":"I feel like a fool when I talk to you.","TWN":"跟你說話感覺自己會變成傻瓜。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PAPERBOY_SWANSONG_NPC_NULL","text":{"KOREA":"호외요~ 호외~!","JPN":"号外！　号外です！","ENG":"Extra, extra! Read all about it!","TWN":"號外號外～號外～！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PAPERBOY_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마가 보낸 성명문을 스트랜드 페이퍼가 어렵게 입수했어요!","JPN":"深夜の殺人鬼が送った声明文を、ストランドペーパーが入手しました！","ENG":"Strand Paper has obtained a statement sent by the Midnight Killer!","TWN":"《斯特蘭德報》艱難獲取了午夜殺手發來的聲明！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PAPERBOY_SWANSONG_NPC_NULL","text":{"KOREA":"단돈 5실링이면, 심야의 살인마의 새로운 범행 예고를 열람하실 수 있답니다!","JPN":"たった5シリングで、深夜の殺人鬼の新たな犯行予告を閲覧できますよ！","ENG":"For just five shillings, you can read about the Midnight Killer's warning of his next crime!","TWN":"只需5分錢，就能查看午夜殺手的新犯罪預告喔！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PAPERBOY_SWANSONG_NPC_NULL","text":{"KOREA":"오늘 밤, 살인마에게 베이지 않게 미리 대비하세요!","JPN":"今夜、殺人鬼に襲われないようにお気をつけて！","ENG":"Tonight, prepare in advance to avoid getting slashed by the Midnight Killer!","TWN":"今晚，提前做好準備，不要被殺手盯上！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"이제는 하다하다 살인마가 성명문까지 보낸다고? 말세로군, 말세야.","JPN":"殺人鬼が声明文だと？　世も末だな。","ENG":"Now even murderers are sending out statements? What has the world become?","TWN":"現在連殺手都開始發佈聲明了？真是末世啊，末世！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"잠깐, 이거 진짜야? 심야의 살인마가 죽인 여자들이 사실…….","JPN":"待てよ、これって本当か？　深夜の殺人鬼が殺した女性たちって実は……","ENG":"Wait, is this real? That the women who fell victim to the Midnight Killer are actually...","TWN":"等一下，這是真的嗎？午夜殺手殺的那些女人其實……"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"저기, 나도 신문 하나만 받을 수 있을까?","JPN":"ねえ、私も新聞を一部もらえるかしら？","ENG":"Hey, could I get a copy?","TWN":"那個，也給我拿一份報紙吧？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"PAPERBOY_SWANSONG_NPC_NULL","text":{"KOREA":"기다리고 있었어, 스완. 네 거는 따로 빼놨거든.","JPN":"待ってたよ、スワン。君の分は取っておいたんだ。","ENG":"I was wondering when you'd come, Swan. I kept a copy for you just in case.","TWN":"我一直在等你呢，史旺。你的那份我已經單獨留出來了！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PAPERBOY_SWANSONG_NPC_NULL","text":{"KOREA":"어라, 그런데 그쪽 신사분은……?","JPN":"あれ、そこの男性の方は……？","ENG":"Huh? Who's the gentleman...?","TWN":"哎，那邊的那位紳士是……？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"아아, 이 남자?","JPN":"ああ、この人は……","ENG":"Oh, this man?","TWN":"啊，這個人？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"신경 쓰지 마. 내 고용인이니까.","JPN":"気にしないで。私の使用人だから。","ENG":"Don't worry about him. He's just one of my employees.","TWN":"別在意他。他是我雇來的。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하하, 이야기는 많이 들었어.","JPN":"はは、話は聞いたよ。","ENG":"Haha. I heard a lot about you.","TWN":"哈哈，我聽說了很多。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아가씨가 매일 신문을 신세 지고 있다지? 잘 부탁한다네.","JPN":"お嬢さんが毎日新聞を愛読しているらしいな。これからもよろしく。","ENG":"You've been providing our lady with a copy of the newspaper every day, right? Thank you for that.","TWN":"你每天都會替小姐留一份報紙呢？真是麻煩你了。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"PAPERBOY_SWANSONG_NPC_NULL","text":{"KOREA":"……아아, 네.","JPN":"……ああ、はい。","ENG":"...Uh, sure.","TWN":"……啊啊，是！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"쳇, 능글맞긴.","JPN":"まったく、図々しいんだから……","ENG":"Tch, you and your sly tongue.","TWN":"嘖，油嘴滑舌。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마 성명문은 1면에 실려있네요.","JPN":"深夜の殺人鬼が送ったという声明文は、1面に載っていますね。","ENG":"The Midnight Killer's statement is on the front page.","TWN":"讓我看看……"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"어디보자…….","JPN":"どれどれ……","ENG":"Let’s see here...","TWN":"午夜殺人魔的聲明登在了頭版。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……친애하는 보스에게.","JPN":"……親愛なるボスへ。","ENG":"...Dear Boss.","TWN":"……親愛的老闆。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"경찰이 날 잡았다는 말이 들려오는데 아직은 날 잡을 수 없을 거다…….","JPN":"警察が私を捕まえたという噂が聞こえるが、まだまだ私は捕まらない……","ENG":"I keep on hearing the police have caught me, but they won't catch me just yet...","TWN":"我不斷地聽到員警已將我逮捕的消息，可他們還沒做到，我很喜歡他們束手無策的樣子……"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그 검은 갑옷에 대한 농담은 꽤 웃겼어. 아무리 나라도 그런 걸 입고 뛰려면 힘들겠군…….","JPN":"あの黒い鎧に関するジョークは結構面白かったよ。いくら私でもあんなものを着て走るのは大変だろう……","ENG":"I had a good laugh about that joke with the black armor. It'll be difficult for even me to run while wearing something like that...","TWN":"當他們自作聰明地聯想到那副黑色盔甲時，我實在忍不住大笑特笑。即使是我，穿著那種東西跑步也會十分吃力……"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……나는 이능자가 혐오스러워 견딜 수 없어.","JPN":"……私は異能力者が忌々しくてならない。","ENG":"...I just despise those Supernaturals.","TWN":"……我無法忍受超能力者，甚至是討厭至極。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그 더러운 표식을 쫓아 전부 잘라낼 때까지 나는 살인을 멈추지 않겠다.","JPN":"あの汚らわしい印を一つ残さずすべて切り落とすまで私は殺人を止めない。","ENG":"My killings won't stop until I find and cut out every last one of those filthy marks.","TWN":"在追蹤那個骯髒的標記並將它們全部切除之前，我不會停止殺戮。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"행운을 빌지, 심야의 살인마로부터.","JPN":"幸運を祈る。深夜の殺人鬼より。","ENG":"Good luck. Yours truly, the Midnight Killer.","TWN":"祝你好運！你真誠的午夜殺人魔。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"흥, 한심하네요.","JPN":"ふん、情けないですね。","ENG":"Hmph. This is pathetic.","TWN":"哼，真是可悲。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"고작 살인이나 저지르는 범죄자 주제에 무슨 대단한 일이라도 벌인 것처럼 떠들어 대다니.","JPN":"ただの犯罪者のくせに、立派なことでもやっているかのように御託を並べて。","ENG":"A lowly criminal justifying his acts of murder as if he's doing something extraordinary.","TWN":"不過是個殺人犯，竟然還大言不慚地炫耀，好像自己幹了什麼了不起的事似的。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"누가 이런다고 겁먹을 줄 알고?","JPN":"だからって誰が怯えるもんですか。","ENG":"Like this is going to scare anyone.","TWN":"就好像會嚇到誰一樣。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 동감이라네.","JPN":"ふふ、同感だよ。","ENG":"Haha. I agree.","TWN":"呵呵，我也有同感呢。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 아무래도 시민들은 그렇게 생각하지 않는 모양이로군.","JPN":"だが、どうやら市民たちはそう思っていないようだ。","ENG":"But the public doesn't seem to see it the way we do.","TWN":"但是看來市民們並不這麼認為。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그래서? 슬슬 말해줄 때도 되지 않았나요?","JPN":"それで、そろそろ教えてくれませんか？","ENG":"So? Isn't it about time you told me?","TWN":"所以？現在可以告訴我了吧？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"음? 무슨 소리지?","JPN":"ん？　なんの話かね？","ENG":"Mm? What are you talking about?","TWN":"嗯？告訴你什麼？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"으으, 또 시치미 떼긴……!","JPN":"うう、またとぼけて……！","ENG":"Errgh! Again with playing dumb...!","TWN":"呃，又在裝蒜……！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신이 그랬잖아요. 심야의 살인마를 막지 못하면 우리 세계가 멸망할 거라나, 뭐라나.","JPN":"あなたが言いましたよね。深夜の殺人鬼を止めないと、世界が滅ぶとかなんとか。","ENG":"You said to me that our world will end or something if we didn't stop the Midnight Killer.","TWN":"你說過的吧。不能阻止午夜殺人魔的話，我們的世界就會滅亡，什麼的。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아아, 그 이야기로군.","JPN":"ああ、その話か。","ENG":"Oh, that's what you were talking about.","TWN":"啊……原來是那件事。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애초에 말이 안 돼요. 런던에서 하루에 얼마나 많은 빈민이 죽거나 사라지는 줄 아세요?","JPN":"そもそも話になりませんけど。ロンドンでは毎日多くの貧民が死んだり失踪したりするんですよ。","ENG":"None of it makes sense in the first place. Do you even know how many poor people die or go missing every day in London?","TWN":"本來就不合理吧？倫敦每天有那麼多的貧民死去或者失蹤。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 누가 죽든 말든 세상은 잘만 돌아가고 있잖아요.","JPN":"それでも何も問題なく、日常は続いている。","ENG":"Yet, the world goes on regardless of who dies.","TWN":"但是不管誰死了，這個世界不還是照樣運轉嗎？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"무고한 이능력자가 끔찍하게 살해당하는 건 참으로 애석한 일이라고 생각해요.","JPN":"罪のない異能力者たちが無残に殺されるのは、とても気の毒だと思います。","ENG":"I do think that it's unfortunate that innocent Supernaturals are being brutally murdered.","TWN":"無辜的超能力者被殘忍殺害，確實會令人痛心。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그래서요? 저는 그런 것보다 배우로서의 제 인생이 훨씬 중요하답니다.","JPN":"でも、それがどうしたと言うんですか？　私はそんなことより、俳優としての私の人生が大事なんです。","ENG":"But so what? For me, my life as an actress is far more important than that.","TWN":"但是那又怎樣？對我來說，作為演員的人生要重要得多。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"적어도 왜 이런 시간 낭비를 해야 하는지, 들을 권리가 있다고 생각하는데요?","JPN":"こんな時間の無駄だとしか思えないことを、しなければならない理由を聞く権利が、私にはあると思いますが？","ENG":"So, don't you think I at least have the right to know why you are wasting my time?","TWN":"至少我有權知道為什麼要浪費時間在這些事情上，不是嗎？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"시간 낭비라. 뭐, 자네처럼 생각하는 것도 무리는 아니지.","JPN":"時間の無駄、か。まあ、そう考えるのも無理はない。","ENG":"Wasting time? I guess you could see it like that.","TWN":"浪費時間嗎。嗯，像你這樣想也不無道理。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그게 꼭 그렇지만도 않다네. 스완.","JPN":"でも、それがそうでもないんだよ。スワン。","ENG":"But that is not always the case, Swan.","TWN":"但這也不一定，史旺。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"무슨 뜻이죠?","JPN":"どういう意味ですか？","ENG":"What do you mean?","TWN":"什麼意思？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그동안 수많은 사건을 해결해 오면서 한가지 깨달은 게 있어.","JPN":"今まで様々な事件を解決してきて、気づいたことがあるんだ。","ENG":"After solving countless cases, there is one thing that I came to realize.","TWN":"在解決了無數案件的過程中，我明白了一件事。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"우리의 운명이라는 보이지 않는 실타래 속에는 사실, 선홍색의 실이 얽혀 있다는 걸.","JPN":"私たちの運命という目に見えない糸には、深紅に染まった糸が絡まっている。","ENG":"It's that within the invisible threads of destiny, our fates are actually intertwined by a bright red thread.","TWN":"在我們那個名為命運的無形線團裡，其實還纏繞著一根鮮紅色的細線。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"언뜻 보면, 전혀 상관없는 것들이……. 복잡하게 얽히고 얽혀 어떤 사건을 만들어 내지.","JPN":"最初は何の関係もなく思えても……いつしか複雑に絡み合い、ある出来事を作り出す。","ENG":"The things that seem unrelated at first glance... get tangled together to create an event.","TWN":"乍一看，是完全無關的事物……複雜地交織在一起，才製造出了某種事件。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그것을 철저하고, 낱낱이 규명하는 것이 나의 업이라네.","JPN":"それを徹底的に、一つ残らず突き詰めることが私の仕事だ。","ENG":"My job is to thoroughly investigate and identify them.","TWN":"徹底而詳細地查明這些，就是我的職責。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"업……?","JPN":"仕事……？","ENG":"Your job...?","TWN":"你的職責……？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네가 말했지? 매일 같이 런던 빈민들이 실종되더라도 세상은 멀쩡히 돌아갈 거라고?","JPN":"君が言っただろう？　毎日ロンドンの貧民が失踪しても、世界は何も問題なく、日常は続くと。","ENG":"You said it yourself. That the world will continue to be fine even if London's poor go missing.","TWN":"你說，即使每天都有倫敦的貧民失蹤，世界也會照常運轉？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마가 누굴 죽이든, 자네와는 전혀 상관없는 일이라고?","JPN":"深夜の殺人鬼が誰を殺そうとも、君とはまったく関係のないことだと。","ENG":"Do you really think the Midnight Killer's murders have nothing to do with you?","TWN":"那麼午夜殺人魔殺了人，就完全和你沒有一點關係了嗎？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그게 정말로 그럴까?","JPN":"だが、本当にそうだろうか。","ENG":"Are you absolutely sure of this?","TWN":"你能確定？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"무엇보다도 말이지.","JPN":"なにより。","ENG":"Above all else.","TWN":"最重要的是。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네와 내가 이렇게 만나게 된 것 자체가 그 훌륭한 반증이지 않은가?","JPN":"君と私がこうして出会えたこと自体、立派な反証ではないだろうか。","ENG":"Isn't the fact that you and I met like this an excellent rebuttal?","TWN":"你和我能這樣相遇，本身就是最好的證明，不是嗎？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그, 그건……!","JPN":"そ、それは……！","ENG":"Th-that's...!","TWN":"那，那個……！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그건 순전히 당신의 오지랖일 뿐이잖아요!","JPN":"あれは、あなたがお節介を焼いただけじゃないですか！","ENG":"That's purely because you're nosy!","TWN":"那純粹是你多管閒事而已！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후. 쓸데없는 오지랖은 내 업의 기본 소양이거든.","JPN":"ふふ、この仕事をやっていくためにお節介は基本なんだ。","ENG":"Haha. Being nosy is a part of my job description.","TWN":"呵呵。愛管閒事也是我的基本職業素養。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"간략히 설명하자면, 이 도시에서 일어나고 있는 연쇄 살인은 일종의 <color=#ffd34c>의식</color>이라고 할 수 있어.","JPN":"簡単に説明すると、今この街で起きている連続殺人は一種の<color=#ffd34c>儀式</color>と言える。","ENG":"Put it simply, the serial killings that have been happening in this city can be seen as some sort of <color=#ffd34c>ritual</color>.","TWN":"簡單來說，這個城市發生的連環殺人案可以說是一種<color=#ffd34c>儀式</color>。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"의식이라고요?","JPN":"儀式？","ENG":"A ritual?","TWN":"儀式？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 아마도 무언가를 이 세계에 불러내기 위한 의식이겠지.","JPN":"ああ、おそらく何かをこの世に呼び出すための儀式なのだろう。","ENG":"Yes. I believe it to be a ritual to summon something into this world.","TWN":"是的，我認為是為了召喚某種東西到這個世界的儀式。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만, 이 세계는 이미 어떤 임계치에 다다른 상태야. 마치 가득 채워진 물컵처럼.","JPN":"だが、この世界はすでに臨界値に達している状態だ。いまにも水が溢れそうなコップみたいにね。","ENG":"But this world has already reached a certain critical point. Much like a full cup of water.","TWN":"這個世界已經達到了某種臨界點。就像一杯裝滿的水。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"위태롭게 표면장력으로 버티고 있지만, 언제 넘쳐 흘러 내용물을 쏟아낼 지 모르지.","JPN":"表面張力でぎりぎり耐えているものの、いつ決壊して中身がこぼれるかわからない。","ENG":"The surface tension is precariously keeping the water from spilling, but it could overflow at any moment.","TWN":"雖然靠著表面張力勉強維持，但不知道什麼時候會溢出來，灑出裡面的內容物。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"표현이 너무 추상적이잖아요. 임계치라는 건 또 뭔데요?","JPN":"表現が抽象的すぎます。臨界値ってなんですか？","ENG":"You're being too abstract. What is the critical point you're talking about?","TWN":"表達得太抽象了吧。所謂的臨界值又是什麼？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 좀 더 와닿는 예시를 들어볼까?","JPN":"じゃあ、もう少しわかりやすい例えをあげてみるか。","ENG":"Then, how about I give another example that's more intuitive to understand.","TWN":"那麼，我來舉個更貼切的例子吧。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이를테면, 수년 전부터 왕국 밖의 마물들이 점점 강해지고 있다던가.","JPN":"例えば、数年前から王国外の魔物がどんどん強くなっていることとか。","ENG":"For instance, monsters outside of the kingdom have been getting stronger for several years now.","TWN":"比如說，數年前開始，王國外的怪物們變得越來越強大了。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"해마다 마석의 조달량이 점점 감소하고 있다던가.","JPN":"毎年魔石の採掘量が減少していることとか。","ENG":"With each passing year, the supply of Mana Stones gradually decreases.","TWN":"每年的魔石供應量都在逐漸減少。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 정체를 알 수 없는 유독한 안개가 점점 짙어지는 게 그 증거라고 할 수 있지.","JPN":"そして得体のしれない有毒性の霧が日に日に濃くなっていることがその証拠だ。","ENG":"Also, the unknown toxic gas getting thicker is another proof.","TWN":"而且，來源不明的有毒霧氣越來越濃，也可以作為一個證據。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이런 임계 상황에서 외부 세계의 무언가를 우리 세계로 끌어들이게 된다면.","JPN":"こういった臨界状態で、外の世界から何かをこちらに呼び出すことになったら。","ENG":"And trying to bring something into our world that is already at this critical point will...","TWN":"在這種臨界的情況下，如果外面有什麼東西想要進來。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"우리 세계는 틀림없이 돌이킬 수 없는 결말을 맞이하고 말 거야.","JPN":"この世界は間違いなく、取り返しのつかない結末を迎えてしまうだろう。","ENG":"force our world into an irreversible end.","TWN":"我們的世界必將迎來無法挽回的結局。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"순 헛소리로군요.","JPN":"ばかげた話ですね。","ENG":"That's nonsense.","TWN":"純屬胡說八道。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"결국, 저를 끌어들인 이유가 결국 그런 미신 때문이라는 건가요?","JPN":"つまり、私を巻き込んだのはあなたの迷信のせいということですか？","ENG":"So you're telling me that you dragged me into this because of some superstition?","TWN":"最終，把我牽扯進來的理由，竟然是因為那種迷信嗎？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"미신이라…….","JPN":"迷信か……","ENG":"Superstition, you say...","TWN":"迷信……嗎？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"뭐, 자네의 입장에서는 그게 미신인지, 아닌지는 그다지 중요하지 않을 텐데?","JPN":"まあ、君からするとそれが本当か迷信かはそこまで重要じゃないはずだ。","ENG":"Well, to you, I don't think it matters if it is or isn't.","TWN":"嗯，從你的立場來看，究竟是迷信還是什麼，應該不那麼重要吧？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네에게 중요한 건……. 역시 <color=#ffd34c>이거</color>겠지?","JPN":"君にとって重要なのは……やはり<color=#ffd34c>これ</color>だろう？","ENG":"What's important to you... is <color=#ffd34c>this</color>, right?","TWN":"對你來說重要的……果然是<color=#ffd34c>這個</color>吧？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"사진……!","JPN":"写真……！","ENG":"The photo...!","TWN":"照片……！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"크읏! 그러니까 부탁하는 방식이 저질이라고요!","JPN":"くっ……！　頼み方が卑怯ですよ！","ENG":"Kghh! The way you ask is disdainful!","TWN":"呃！所以說你拜託人的方式太差勁了！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하하, 그럴지도 모르겠군.","JPN":"はは、そうかもしれないな。","ENG":"Haha, perhaps it is.","TWN":"哈哈，也許吧。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"부디, 무례를 용서해주게. 내게 허락된 시간이 이제 얼마 남지 않았거든.","JPN":"どうか無礼を許してくれたまえ。もう私に残された時間があまりないのだ。","ENG":"But please forgive my rudeness. My time is running out.","TWN":"請原諒我的無禮。但留給我的時間已經不多了。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……시간?","JPN":"……時間？","ENG":"...Time?","TWN":"……時間？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자, 어쨌거나 수사를 시작하도록 하지.","JPN":"さて、捜査を始めよう。","ENG":"Now, let's start investigating.","TWN":"好了，不管怎樣，開始調查吧。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"지금부터 모든 수사 과정을 놓치지 않고 꼼꼼히 머릿속에 담아두길 바라네.","JPN":"今から行われる捜査過程を、一つ残らず全部頭に入れてほしい。","ENG":"From now on, I want you to memorize all of the investigation process without missing any details.","TWN":"從現在開始，希望你能仔細記住調查過程中的任何細節。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"저 남자…….","JPN":"あの男……","ENG":"This man...","TWN":"那個男人……"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"분명 나를 고급 메모장 정도로 생각하고 있는 게 틀림없어.","JPN":"絶対私を歩くメモ帳ぐらいにしか思っていないわ。","ENG":"I'm sure that he's thinking of me as nothing more than a fancy notepad.","TWN":"分明是把我當成高級記事本了。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"뭐 하고 있나? 마차를 잡아두었네.","JPN":"何をしている？　馬車を手配した。","ENG":"What are you doing? I already got us a carriage.","TWN":"還在等什麼呢？馬車已經備好了。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"빨리 안 오면, 걸어서 목적지까지 가게 될 텐데?","JPN":"早く来ないと、目的地まで歩くことになるのだが。","ENG":"If you don't hurry, you'll be walking all the way to our destination.","TWN":"再不快點來，就要走路到目的地了？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그래요, 간다고요! 가!","JPN":"はい、はい。行きますってば！","ENG":"Coming! I'm coming!","TWN":"好吧，我去還不行嗎！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};